refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/opencv_left01.jpg"));
image = imresize(rgb2gray(image), [64 96]);
blurred = imgaussianblur(image, [9 9], 2);
psf = imfspecial("gaussian", 9, 2);
restored = imdeconvblind(blurred, psf, 8);
subplot(1, 3, 1);
imshow(image);
subplot(1, 3, 2);
imshow(blurred);
subplot(1, 3, 3);
imshow(restored);
